import{_ as t,o as a,c as r,a2 as s}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"Creature Feature","description":"","frontmatter":{},"headers":[],"relativePath":"formats/creature-feature/index.md","filePath":"formats/creature-feature/index.md","lastUpdated":null}'),n={name:"formats/creature-feature/index.md"};function i(u,e,o,l,h,c){return a(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="creature-feature" tabindex="-1">Creature Feature <a class="header-anchor" href="#creature-feature" aria-label="Permalink to &quot;Creature Feature&quot;">​</a></h1><p>Creature Feature is a local Pegasus Loft constructed format that uses normal Magic gameplay, but adds deck-building pressure around creature density and shared creature types.</p><h2 id="core-rules" tabindex="-1">Core Rules <a class="header-anchor" href="#core-rules" aria-label="Permalink to &quot;Core Rules&quot;">​</a></h2><ul><li>Decks have a <strong>60-card minimum</strong>.</li><li>At least <strong>half of the deck</strong> must be creature cards, rounded up.</li><li>At least <strong>two thirds of the creature cards</strong> in the deck must share a creature type, rounded up.</li><li>Games are played as normal Magic unless the event organizer announces an additional house rule.</li><li>Use normal constructed deck-building rules unless the event organizer announces otherwise.</li></ul><h2 id="creature-type-requirement" tabindex="-1">Creature Type Requirement <a class="header-anchor" href="#creature-type-requirement" aria-label="Permalink to &quot;Creature Type Requirement&quot;">​</a></h2><p>Choose one creature type as the deck&#39;s featured type. A creature card counts toward the shared-type requirement if its Oracle creature types include the featured type.</p><p>For example:</p><ul><li>A 60-card deck needs at least 30 creature cards.</li><li>If that deck has 30 creature cards, at least 20 of those creatures must share the featured type.</li><li>If that deck has 31 creature cards, at least 21 of those creatures must share the featured type.</li></ul><p>Creatures with multiple creature types can count for any type they have. Changelings count as having every creature type unless the event organizer has separately banned or restricted that interaction.</p><h2 id="temporary-type-bans" tabindex="-1">Temporary Type Bans <a class="header-anchor" href="#temporary-type-bans" aria-label="Permalink to &quot;Temporary Type Bans&quot;">​</a></h2><p>When a creature type wins a Creature Feature tournament, that creature type should be temporarily banned for the next four weeks.</p><p>The goal is to keep dominant types from repeating every event, especially creature types with deep tribal support such as Eldrazi or Sliver. After the temporary ban expires, the type becomes legal again unless it wins another event.</p><h2 id="negative-creature-type-hate" tabindex="-1">Negative Creature-Type Hate <a class="header-anchor" href="#negative-creature-type-hate" aria-label="Permalink to &quot;Negative Creature-Type Hate&quot;">​</a></h2><p>Cards that negatively target creature types are banned.</p><p>This includes cards whose main purpose is to punish, remove, shrink, prevent, or otherwise disadvantage a named creature type. Color hate, mana-value hate, graveyard hate, artifact hate, and other non-type-specific answers are still legal unless they are banned by another rule.</p><p>Use this as the practical test: if the card asks a player to choose or name a creature type and then harms that type or gives protection from that type, it should not be played in Creature Feature.</p><h2 id="event-notes" tabindex="-1">Event Notes <a class="header-anchor" href="#event-notes" aria-label="Permalink to &quot;Event Notes&quot;">​</a></h2><ul><li>Keep a visible list of currently banned creature types and the date each ban expires.</li><li>Record the winning featured type after each event.</li><li>If a winning deck uses multiple creature types heavily, ban the type that satisfied the two-thirds requirement.</li><li>If the event uses sideboards, the deck should still satisfy the creature-count and shared-type requirements after sideboarding.</li></ul>',18)])])}const y=t(n,[["render",i]]);export{p as __pageData,y as default};
